def create_files():
    files = {
        "frontend/src/pages/WebsiteScanner.tsx": "import React, { useState } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { Globe, ArrowRight, ShieldCheck, Search } from 'lucide-react';\n\nconst WebsiteScanner = () => {\n  const [url, setUrl] = useState('');\n  const [isScanning, setIsScanning] = useState(false);\n  const [progress, setProgress] = useState(0);\n  const navigate = useNavigate();\n\n  const handleScan = (e: React.FormEvent) => {\n    e.preventDefault();\n    if (!url) return;\n    setIsScanning(true);\n    \n    // Simulate scanning process\n    let currentProgress = 0;\n    const interval = setInterval(() => {\n      currentProgress += 5;\n      setProgress(currentProgress);\n      if (currentProgress >= 100) {\n        clearInterval(interval);\n        setTimeout(() => {\n          navigate(`/app/results/mock-id`);\n        }, 500);\n      }\n    }, 100);\n  };\n\n  return (\n    <div className=\"max-w-3xl mx-auto space-y-8\">\n      <div className=\"text-center space-y-4 mb-12\">\n        <div className=\"w-16 h-16 mx-auto bg-primary/20 rounded-full flex items-center justify-center\">\n          <Globe className=\"text-primary w-8 h-8\" />\n        </div>\n        <h1 className=\"text-3xl font-bold\">Website Scanner</h1>\n        <p className=\"text-gray-400\">Enter a URL to analyze it against multiple threat intelligence feeds.</p>\n      </div>\n\n      <motion.div \n        initial={{ opacity: 0, y: 20 }}\n        animate={{ opacity: 1, y: 0 }}\n        className=\"glass-panel p-8\"\n      >\n        <form onSubmit={handleScan} className=\"space-y-6\">\n          <div>\n            <label className=\"block text-sm font-medium text-gray-300 mb-2\">Target URL</label>\n            <div className=\"relative\">\n              <div className=\"absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none\">\n                <Search className=\"h-5 w-5 text-gray-500\" />\n              </div>\n              <input \n                type=\"url\" \n                required\n                placeholder=\"https://example.com\"\n                className=\"w-full bg-surface border border-border rounded-xl pl-12 pr-4 py-4 text-white focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary transition-colors\"\n                value={url}\n                onChange={(e) => setUrl(e.target.value)}\n                disabled={isScanning}\n              />\n            </div>\n          </div>\n\n          {isScanning ? (\n            <div className=\"space-y-3\">\n              <div className=\"flex justify-between text-sm\">\n                <span className=\"text-primary font-medium animate-pulse\">Agents Analyzing...</span>\n                <span className=\"text-gray-400\">{progress}%</span>\n              </div>\n              <div className=\"w-full bg-surface rounded-full h-2.5 overflow-hidden\">\n                <motion.div \n                  className=\"bg-gradient-to-r from-primary to-accent h-2.5 rounded-full\"\n                  initial={{ width: 0 }}\n                  animate={{ width: `${progress}%` }}\n                  transition={{ duration: 0.1 }}\n                ></motion.div>\n              </div>\n            </div>\n          ) : (\n            <button \n              type=\"submit\"\n              className=\"w-full btn-primary flex items-center justify-center gap-2 py-4\"\n            >\n              Start Analysis <ArrowRight size={20} />\n            </button>\n          )}\n        </form>\n      </motion.div>\n      \n      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-4 mt-8 opacity-60\">\n         <div className=\"glass-card p-4 flex items-start gap-3\">\n            <ShieldCheck className=\"text-success mt-1 shrink-0\" />\n            <div>\n              <h4 className=\"font-medium text-sm\">Secure Execution</h4>\n              <p className=\"text-xs text-gray-400\">Scans run in isolated sandboxes.</p>\n            </div>\n         </div>\n         <div className=\"glass-card p-4 flex items-start gap-3\">\n            <ShieldCheck className=\"text-success mt-1 shrink-0\" />\n            <div>\n              <h4 className=\"font-medium text-sm\">Privacy First</h4>\n              <p className=\"text-xs text-gray-400\">We do not store your private payloads.</p>\n            </div>\n         </div>\n      </div>\n    </div>\n  );\n};\n\nexport default WebsiteScanner;\n",
        "frontend/src/pages/QRScanner.tsx": "import React, { useState, useRef } from 'react';\nimport { useNavigate } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { QrCode, Upload, Camera, ArrowRight } from 'lucide-react';\n\nconst QRScanner = () => {\n  const [isScanning, setIsScanning] = useState(false);\n  const [file, setFile] = useState<File | null>(null);\n  const navigate = useNavigate();\n  const fileInputRef = useRef<HTMLInputElement>(null);\n\n  const handleSimulateScan = () => {\n    setIsScanning(true);\n    setTimeout(() => {\n      navigate(`/app/results/mock-qr-id`);\n    }, 2000);\n  };\n\n  return (\n    <div className=\"max-w-3xl mx-auto space-y-8\">\n      <div className=\"text-center space-y-4 mb-12\">\n        <div className=\"w-16 h-16 mx-auto bg-accent/20 rounded-full flex items-center justify-center\">\n          <QrCode className=\"text-accent w-8 h-8\" />\n        </div>\n        <h1 className=\"text-3xl font-bold\">QR Code Scanner</h1>\n        <p className=\"text-gray-400\">Upload a QR image or use your camera to detect malicious payloads.</p>\n      </div>\n\n      <div className=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n        <motion.div \n          initial={{ opacity: 0, scale: 0.95 }}\n          animate={{ opacity: 1, scale: 1 }}\n          className=\"glass-panel p-8 text-center flex flex-col items-center justify-center border-dashed border-2 border-border hover:border-accent/50 cursor-pointer transition-colors\"\n          onClick={() => fileInputRef.current?.click()}\n        >\n          <input \n            type=\"file\" \n            ref={fileInputRef} \n            className=\"hidden\"\n            accept=\"image/*\" \n            onChange={(e) => { \n              if(e.target.files && e.target.files[0]) { \n                setFile(e.target.files[0]); \n                handleSimulateScan(); \n              } \n            }}\n          />\n          <Upload className=\"w-12 h-12 text-gray-500 mb-4\" />\n          <h3 className=\"font-bold mb-2\">Upload Image</h3>\n          <p className=\"text-sm text-gray-400\">Drop your QR code here or browse</p>\n        </motion.div>\n\n        <motion.div \n          initial={{ opacity: 0, scale: 0.95 }}\n          animate={{ opacity: 1, scale: 1 }}\n          transition={{ delay: 0.1 }}\n          className=\"glass-panel p-8 text-center flex flex-col items-center justify-center hover:bg-white/5 cursor-pointer transition-colors\"\n          onClick={handleSimulateScan}\n        >\n          <Camera className=\"w-12 h-12 text-gray-500 mb-4\" />\n          <h3 className=\"font-bold mb-2\">Use Camera</h3>\n          <p className=\"text-sm text-gray-400\">Scan directly from your device</p>\n        </motion.div>\n      </div>\n\n      {isScanning && (\n        <motion.div \n          initial={{ opacity: 0 }}\n          animate={{ opacity: 1 }}\n          className=\"glass-panel p-6 text-center\"\n        >\n          <div className=\"animate-pulse-slow flex flex-col items-center\">\n            <QrCode className=\"text-accent w-10 h-10 mb-4 animate-bounce\" />\n            <p className=\"font-medium text-accent\">Decoding and Analyzing Vector...</p>\n          </div>\n        </motion.div>\n      )}\n    </div>\n  );\n};\n\nexport default QRScanner;\n",
        "frontend/src/pages/Results.tsx": "import React from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { AlertTriangle, ShieldCheck, Download, ExternalLink, ArrowLeft, Info, CheckCircle2, XCircle } from 'lucide-react';\n\nconst Results = () => {\n  const { id } = useParams();\n  const navigate = useNavigate();\n  \n  // Realistic Mock Data for \"mock-id\"\n  const mockData = {\n    target: \"https://secure-login-paypal.com/auth\",\n    riskScore: 92,\n    level: \"Critical\",\n    statusColor: \"text-danger\",\n    statusBg: \"bg-danger/10\",\n    statusBorder: \"border-danger/30\",\n    recommendation: \"Do not proceed. This site exhibits multiple characteristics of a credential harvesting phishing attack.\",\n    agents: [\n      { name: \"WHOIS Agent\", status: \"Fail\", desc: \"Domain registered 3 days ago. Registrar is anonymous.\", pass: false },\n      { name: \"SSL Agent\", status: \"Warn\", desc: \"Valid Let's Encrypt cert, but frequently used by threat actors.\", pass: false },\n      { name: \"Threat Intel Agent\", status: \"Fail\", desc: \"Flagged by 4 security vendors in the last 24 hours.\", pass: false },\n      { name: \"Typo Squatting Agent\", status: \"Fail\", desc: \"Imitates 'paypal.com' but uses a malicious sub-path structure.\", pass: false }\n    ]\n  };\n\n  const radius = 60;\n  const circumference = 2 * Math.PI * radius;\n  const strokeDashoffset = circumference - (mockData.riskScore / 100) * circumference;\n\n  return (\n    <div className=\"max-w-5xl mx-auto space-y-8\">\n      <button onClick={() => navigate(-1)} className=\"flex items-center gap-2 text-gray-400 hover:text-white transition-colors\">\n        <ArrowLeft size={16} /> Back\n      </button>\n\n      <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n        {/* Left Column: Gauge and Primary Verdict */}\n        <div className=\"space-y-6\">\n          <motion.div \n            initial={{ opacity: 0, x: -20 }}\n            animate={{ opacity: 1, x: 0 }}\n            className=\"glass-panel p-8 text-center flex flex-col items-center relative\"\n          >\n            <h2 className=\"text-gray-400 font-medium uppercase tracking-widest mb-8\">Risk Assessment</h2>\n            \n            {/* Animated SVG Gauge */}\n            <div className=\"relative w-48 h-48 flex items-center justify-center mb-6\">\n              <svg className=\"transform -rotate-90 w-48 h-48\">\n                <circle cx=\"96\" cy=\"96\" r={radius} className=\"stroke-surface stroke-[12] fill-transparent\" />\n                <motion.circle \n                  cx=\"96\" \n                  cy=\"96\" \n                  r={radius} \n                  className=\"stroke-danger stroke-[12] fill-transparent\"\n                  strokeDasharray={circumference}\n                  initial={{ strokeDashoffset: circumference }}\n                  animate={{ strokeDashoffset }}\n                  transition={{ duration: 1.5, ease: \"easeOut\" }}\n                  strokeLinecap=\"round\"\n                />\n              </svg>\n              <div className=\"absolute inset-0 flex flex-col items-center justify-center\">\n                <span className=\"text-5xl font-extrabold\">{mockData.riskScore}</span>\n                <span className=\"text-sm text-gray-400\">/ 100</span>\n              </div>\n            </div>\n            \n            <div className={`px-4 py-1.5 rounded-full font-bold uppercase tracking-wider text-sm ${mockData.statusBg} ${mockData.statusColor} ${mockData.statusBorder} border mb-2`}>\n              {mockData.level} Risk\n            </div>\n          </motion.div>\n\n          <div className=\"glass-panel p-6\">\n            <h3 className=\"font-bold mb-4 flex items-center gap-2\">\n              <Info size={18} className=\"text-primary\" /> Recommendation\n            </h3>\n            <p className=\"text-gray-300 leading-relaxed\">\n              {mockData.recommendation}\n            </p>\n          </div>\n        </div>\n\n        {/* Right Column: Details and Agents */}\n        <div className=\"lg:col-span-2 space-y-6\">\n          <motion.div \n            initial={{ opacity: 0, y: 20 }}\n            animate={{ opacity: 1, y: 0 }}\n            className=\"glass-panel p-8\"\n          >\n            <div className=\"flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8\">\n              <div>\n                <h2 className=\"text-xl font-bold mb-1\">Analysis Report</h2>\n                <p className=\"text-gray-400 text-sm truncate max-w-sm\">{mockData.target}</p>\n              </div>\n              <button className=\"btn-secondary flex items-center gap-2 shrink-0\">\n                <Download size={16} /> Export PDF\n              </button>\n            </div>\n\n            <div className=\"space-y-4\">\n              <h3 className=\"text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4\">Agent Breakdowns</h3>\n              {mockData.agents.map((agent, idx) => (\n                <motion.div \n                  key={idx}\n                  initial={{ opacity: 0, x: 20 }}\n                  animate={{ opacity: 1, x: 0 }}\n                  transition={{ delay: 0.2 + (idx * 0.1) }}\n                  className=\"p-4 bg-surface/50 border border-border rounded-xl flex items-start gap-4\"\n                >\n                  <div className=\"mt-1 shrink-0\">\n                    {agent.pass ? <CheckCircle2 className=\"text-success\" size={20} /> : <XCircle className=\"text-danger\" size={20} />}\n                  </div>\n                  <div>\n                    <h4 className=\"font-semibold mb-1\">{agent.name}</h4>\n                    <p className=\"text-gray-400 text-sm\">{agent.desc}</p>\n                  </div>\n                </motion.div>\n              ))}\n            </div>\n          </motion.div>\n        </div>\n      </div>\n    </div>\n  );\n};\n\nexport default Results;\n",
        "frontend/src/pages/History.tsx": "import React from 'react';\nimport { motion } from 'framer-motion';\nimport { Search, Filter, ShieldCheck, AlertTriangle } from 'lucide-react';\n\nconst History = () => {\n  const scans = [\n    { id: \"1\", target: \"https://secure-login-paypal.com\", date: \"2026-07-07 10:45 AM\", risk: 98, type: \"URL\" },\n    { id: \"2\", target: \"https://github.com\", date: \"2026-07-06 04:20 PM\", risk: 2, type: \"URL\" },\n    { id: \"3\", target: \"QR Code Image\", date: \"2026-07-06 11:15 AM\", risk: 15, type: \"QR\" },\n    { id: \"4\", target: \"https://free-crypto-giveaway.net\", date: \"2026-07-05 09:30 PM\", risk: 85, type: \"URL\" },\n    { id: \"5\", target: \"https://vercel.com\", date: \"2026-07-04 02:10 PM\", risk: 0, type: \"URL\" },\n  ];\n\n  return (\n    <div className=\"space-y-6\">\n      <div className=\"flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4\">\n        <h1 className=\"text-3xl font-bold\">Scan History</h1>\n        <div className=\"flex gap-2 w-full sm:w-auto\">\n          <div className=\"relative flex-1 sm:w-64\">\n            <Search className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 w-4 h-4\" />\n            <input \n              type=\"text\" \n              placeholder=\"Search targets...\"\n              className=\"w-full bg-surface border border-border rounded-lg pl-9 pr-4 py-2 text-sm focus:outline-none focus:border-primary\"\n            />\n          </div>\n          <button className=\"bg-surface border border-border p-2 rounded-lg hover:bg-white/5 transition\">\n            <Filter size={18} className=\"text-gray-400\" />\n          </button>\n        </div>\n      </div>\n\n      <motion.div \n        initial={{ opacity: 0, y: 10 }}\n        animate={{ opacity: 1, y: 0 }}\n        className=\"glass-panel overflow-hidden\"\n      >\n        <div className=\"overflow-x-auto\">\n          <table className=\"w-full text-left border-collapse\">\n            <thead>\n              <tr className=\"bg-surface/80 border-b border-border\">\n                <th className=\"p-4 font-semibold text-gray-400 text-sm\">Target</th>\n                <th className=\"p-4 font-semibold text-gray-400 text-sm\">Date</th>\n                <th className=\"p-4 font-semibold text-gray-400 text-sm\">Type</th>\n                <th className=\"p-4 font-semibold text-gray-400 text-sm\">Risk Score</th>\n                <th className=\"p-4 font-semibold text-gray-400 text-sm\">Status</th>\n              </tr>\n            </thead>\n            <tbody className=\"divide-y divide-border\">\n              {scans.map((scan) => (\n                <tr key={scan.id} className=\"hover:bg-white/5 transition-colors\">\n                  <td className=\"p-4 font-medium max-w-[200px] truncate\">{scan.target}</td>\n                  <td className=\"p-4 text-sm text-gray-400\">{scan.date}</td>\n                  <td className=\"p-4 text-sm\">{scan.type}</td>\n                  <td className=\"p-4\">\n                    <div className=\"flex items-center gap-2\">\n                      <div className=\"w-16 h-2 bg-surface rounded-full overflow-hidden\">\n                        <div \n                          className={`h-full ${scan.risk > 50 ? 'bg-danger' : 'bg-success'}`}\n                          style={{ width: `${scan.risk}%` }}\n                        ></div>\n                      </div>\n                      <span className=\"text-xs font-bold\">{scan.risk}</span>\n                    </div>\n                  </td>\n                  <td className=\"p-4\">\n                    {scan.risk > 50 ? (\n                      <span className=\"inline-flex items-center gap-1 text-xs font-bold text-danger bg-danger/10 px-2 py-1 rounded\">\n                        <AlertTriangle size={12} /> Malicious\n                      </span>\n                    ) : (\n                      <span className=\"inline-flex items-center gap-1 text-xs font-bold text-success bg-success/10 px-2 py-1 rounded\">\n                        <ShieldCheck size={12} /> Safe\n                      </span>\n                    )}\n                  </td>\n                </tr>\n              ))}\n            </tbody>\n          </table>\n        </div>\n        <div className=\"p-4 border-t border-border flex justify-between items-center text-sm text-gray-400\">\n          <span>Showing 1 to 5 of 5 entries</span>\n          <div className=\"flex gap-2\">\n             <button className=\"px-3 py-1 bg-surface border border-border rounded hover:bg-white/5 disabled:opacity-50\" disabled>Previous</button>\n             <button className=\"px-3 py-1 bg-surface border border-border rounded hover:bg-white/5 disabled:opacity-50\" disabled>Next</button>\n          </div>\n        </div>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default History;\n",
        "frontend/src/pages/Settings.tsx": "import React from 'react';\nimport { motion } from 'framer-motion';\nimport { Moon, Bell, Shield, Lock } from 'lucide-react';\n\nconst Settings = () => {\n  return (\n    <div className=\"max-w-4xl space-y-8\">\n      <div>\n        <h1 className=\"text-3xl font-bold mb-2\">Settings</h1>\n        <p className=\"text-gray-400\">Manage your preferences and workspace configurations.</p>\n      </div>\n\n      <motion.div \n        initial={{ opacity: 0, y: 10 }}\n        animate={{ opacity: 1, y: 0 }}\n        className=\"glass-panel divide-y divide-border\"\n      >\n        {/* Section 1 */}\n        <div className=\"p-8 flex flex-col sm:flex-row sm:items-center justify-between gap-6\">\n          <div className=\"flex gap-4\">\n            <div className=\"w-10 h-10 rounded-full bg-surface flex items-center justify-center shrink-0\">\n              <Moon size={20} className=\"text-gray-300\" />\n            </div>\n            <div>\n              <h3 className=\"font-bold mb-1\">Appearance</h3>\n              <p className=\"text-sm text-gray-400\">Customize the UI theme. Currently locked to Dark Mode for premium aesthetics.</p>\n            </div>\n          </div>\n          <div className=\"flex bg-surface p-1 rounded-lg border border-border shrink-0\">\n            <button className=\"px-4 py-1.5 text-sm font-medium rounded-md text-gray-400 hover:text-white transition\">Light</button>\n            <button className=\"px-4 py-1.5 text-sm font-medium rounded-md bg-white/10 text-white shadow transition\">Dark</button>\n          </div>\n        </div>\n\n        {/* Section 2 */}\n        <div className=\"p-8 flex flex-col sm:flex-row sm:items-center justify-between gap-6\">\n          <div className=\"flex gap-4\">\n            <div className=\"w-10 h-10 rounded-full bg-surface flex items-center justify-center shrink-0\">\n              <Bell size={20} className=\"text-gray-300\" />\n            </div>\n            <div>\n              <h3 className=\"font-bold mb-1\">Notifications</h3>\n              <p className=\"text-sm text-gray-400\">Receive alerts when a scan detects a high-risk payload.</p>\n            </div>\n          </div>\n          <label className=\"relative inline-flex items-center cursor-pointer shrink-0\">\n            <input type=\"checkbox\" className=\"sr-only peer\" defaultChecked />\n            <div className=\"w-11 h-6 bg-surface peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-gray-300 after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-primary\"></div>\n          </label>\n        </div>\n\n        {/* Section 3 */}\n        <div className=\"p-8 flex flex-col sm:flex-row sm:items-center justify-between gap-6\">\n          <div className=\"flex gap-4\">\n            <div className=\"w-10 h-10 rounded-full bg-surface flex items-center justify-center shrink-0\">\n              <Shield size={20} className=\"text-gray-300\" />\n            </div>\n            <div>\n              <h3 className=\"font-bold mb-1\">Aggressive Scanning</h3>\n              <p className=\"text-sm text-gray-400\">Enable advanced heuristics. May increase scan duration.</p>\n            </div>\n          </div>\n          <label className=\"relative inline-flex items-center cursor-pointer shrink-0\">\n            <input type=\"checkbox\" className=\"sr-only peer\" />\n            <div className=\"w-11 h-6 bg-surface peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-gray-300 after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-primary\"></div>\n          </label>\n        </div>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default Settings;\n",
        "frontend/src/pages/Profile.tsx": "import React from 'react';\nimport { motion } from 'framer-motion';\nimport { User, Mail, Key } from 'lucide-react';\n\nconst Profile = () => {\n  return (\n    <div className=\"max-w-3xl mx-auto space-y-8\">\n      <h1 className=\"text-3xl font-bold\">My Profile</h1>\n      \n      <motion.div \n        initial={{ opacity: 0, y: 10 }}\n        animate={{ opacity: 1, y: 0 }}\n        className=\"glass-panel overflow-hidden\"\n      >\n        <div className=\"bg-gradient-to-r from-primary/20 to-accent/20 h-32\"></div>\n        <div className=\"px-8 pb-8\">\n          <div className=\"-mt-12 mb-6 flex justify-between items-end\">\n            <div className=\"w-24 h-24 rounded-2xl bg-surface border-4 border-background flex items-center justify-center shadow-xl\">\n              <User size={40} className=\"text-gray-400\" />\n            </div>\n            <button className=\"btn-secondary text-sm px-4 py-2\">Edit Profile</button>\n          </div>\n          \n          <div className=\"space-y-6\">\n            <div className=\"grid grid-cols-1 sm:grid-cols-2 gap-6\">\n              <div>\n                <label className=\"block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2\">Full Name</label>\n                <div className=\"bg-surface px-4 py-3 rounded-lg border border-border text-white\">Admin User</div>\n              </div>\n              <div>\n                <label className=\"block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2\">Email Address</label>\n                <div className=\"bg-surface px-4 py-3 rounded-lg border border-border text-white flex items-center gap-2\">\n                  <Mail size={16} className=\"text-gray-400\" /> admin@trustguard.ai\n                </div>\n              </div>\n            </div>\n            \n            <div className=\"pt-6 border-t border-border\">\n              <h3 className=\"font-bold mb-4 flex items-center gap-2\">\n                <Key size={18} className=\"text-primary\" /> Authentication\n              </h3>\n              <button className=\"btn-secondary text-sm\">Change Password</button>\n            </div>\n          </div>\n        </div>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default Profile;\n",
        "frontend/src/pages/NotFound.tsx": "import React from 'react';\nimport { Link } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { ShieldAlert } from 'lucide-react';\n\nconst NotFound = () => {\n  return (\n    <div className=\"min-h-screen bg-background flex flex-col items-center justify-center p-6 text-center\">\n      <motion.div\n        initial={{ scale: 0.8, opacity: 0 }}\n        animate={{ scale: 1, opacity: 1 }}\n        transition={{ type: 'spring', bounce: 0.5 }}\n      >\n        <ShieldAlert size={100} className=\"text-primary/50 mx-auto mb-8\" />\n        <h1 className=\"text-7xl font-extrabold text-transparent bg-clip-text bg-gradient-to-br from-white to-gray-500 mb-4\">\n          404\n        </h1>\n        <h2 className=\"text-2xl font-bold mb-4\">Page Not Found</h2>\n        <p className=\"text-gray-400 max-w-md mx-auto mb-8\">\n          The page you are looking for has been moved, deleted, or possibly quarantined by our agents.\n        </p>\n        <Link to=\"/app\" className=\"btn-primary\">\n          Return to Dashboard\n        </Link>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default NotFound;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Frontend Phase 6 (Part 2) scaffolded.")
